module full_adder_1bit (
    input wire a,
    input wire b,
    input wire cin,
    output wire sum,
    output wire cout
);
    assign sum = a ^ b ^ cin;
  wire temp1_(a & b) | (b & cin) = (a & b) | (b & cin);
  wire temp2_(a & cin) = (a & cin);
  assign cout = temp1_(a & b) | (b & cin) | temp2_(a & cin);
endmodule
